// Extract message and determine intent
const body = $input.first().json.body;
const message = body.payload?.content?.toLowerCase() || '';

// Detect escalation triggers
const escalationTriggers = [
  'human', 'agent', 'person', 'representative', 'support',
  'supervisor', 'manager', 'speak to someone', 'talk to',
  'frustrated', 'angry', 'complaint', 'refund', 'cancel'
];

const shouldEscalate = escalationTriggers.some(trigger => message.includes(trigger));

// Detect sentiment (simple keyword-based)
const negativeWords = ['bad', 'terrible', 'awful', 'hate', 'worst', 'angry', 'frustrated', 'upset'];
const sentiment = negativeWords.some(w => message.includes(w)) ? 'negative' : 'neutral';

return {
  json: {
    sessionId: body.sessionId,
    tenantId: body.tenantId,
    userMessage: body.payload?.content,
    messageType: body.payload?.type,
    user: body.user,
    previousMessages: body.context?.previousMessages || [],
    shouldEscalate,
    sentiment,
    pageUrl: body.context?.pageUrl
  }
};

// Generate conversation summary for agent
const data = $input.first().json;
const previousMessages = data.previousMessages;

// Create summary of conversation
let summary = '## Conversation Summary\n\n';
summary += `**Customer:** ${data.user?.name || 'Anonymous'}\n`;
summary += `**Sentiment:** ${data.sentiment}\n`;
summary += `**Page:** ${data.pageUrl || 'N/A'}\n\n`;

if (previousMessages.length > 0) {
  summary += '**Recent Messages:**\n';
  previousMessages.slice(-5).forEach(msg => {
    summary += `- ${msg.role}: ${msg.content.substring(0, 100)}${msg.content.length > 100 ? '...' : ''}\n`;
  });
} else {
  summary += `**Message:** ${data.userMessage}\n`;
}

return {
  json: {
    sessionId: data.sessionId,
    tenantId: data.tenantId,
    summary: summary,
    sentiment: data.sentiment,
    userMessage: data.userMessage,
    priority: data.sentiment === 'negative' ? 'high' : 'normal'
  }
};

// Send handoff trigger to chatbot platform
const data = $('Create Summary').first().json;

return {
  json: {
    action: 'handsoff.trigger',
    sessionId: data.sessionId,
    payload: {
      reason: 'Customer requested human agent',
      priority: data.priority,
      queue: data.priority === 'high' ? 'priority_support' : 'general_support',
      summary: data.summary,
      tags: ['escalated', data.sentiment]
    }
  }
};

// Send acknowledgment to customer
const data = $('Analyze Intent').first().json;

const responses = {
  high: "I understand your frustration. I'm connecting you with a specialist who can help resolve this issue immediately.\n\nEstimated wait time: 2-3 minutes.",
  normal: "I'll connect you with one of our support agents who can assist you further.\n\nEstimated wait time: 5-10 minutes."
};

const priority = data.sentiment === 'negative' ? 'high' : 'normal';

return {
  json: {
    action: 'message.send',
    sessionId: data.sessionId,
    payload: {
      type: 'text',
      content: responses[priority],
      quickReplies: priority === 'high' ? ['Cancel request'] : ['Leave message', 'Cancel request']
    }
  }
};

// Handle non-escalation messages
const data = $input.first().json;

return {
  json: {
    action: 'message.send',
    sessionId: data.sessionId,
    payload: {
      type: 'text',
      content: "I can help you with that! What specific information are you looking for?",
      quickReplies: ['Product info', 'Pricing', 'Support', 'Talk to human']
    }
  }
};

// Send Slack notification for high priority
const data = $('Create Summary').first().json;

return {
  json: {
    text: `🚨 *High Priority Handoff Request*\n\nSession: ${data.sessionId}\nPriority: ${data.priority}\nSentiment: ${data.sentiment}\n\n${data.summary}`
  }
};
